// ======================================================================
// HELPERS de fecha (timezone Argentina)
// ======================================================================
function fmtArgentina(d) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Argentina/Buenos_Aires',
    year: 'numeric', month: '2-digit', day: '2-digit'
  }).formatToParts(d);
  const y = parts.find(p => p.type === 'year').value;
  const m = parts.find(p => p.type === 'month').value;
  const dd = parts.find(p => p.type === 'day').value;
  return `${y}-${m}-${dd}`;
}

function addDays(yyyy_mm_dd, n) {
  const [y, m, d] = yyyy_mm_dd.split('-').map(Number);
  const date = new Date(Date.UTC(y, m - 1, d));
  date.setUTCDate(date.getUTCDate() + n);
  const yy = date.getUTCFullYear();
  const mm = String(date.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(date.getUTCDate()).padStart(2, '0');
  return `${yy}-${mm}-${dd}`;
}

function hoyArgentina() {
  return fmtArgentina(new Date());
}

// ======================================================================
// INPUT
// ======================================================================
const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const comando = input.comando || 'crear';
const textRaw = String(input.text || '');
const payload = input.payload || {};

let fecha = payload.fecha || '';
let slot = payload.slot || '';
let slotNumero = payload.slot_numero || 0;
let rango = payload.rango || '';
let fechaRaw = payload.fecha_raw || '';
let accion = '';
let mensajeError = '';

// ======================================================================
// STATIC DATA: memoria persistente del workflow
// ======================================================================
const staticData = $getWorkflowStaticData('global');
const ctxKey = chatId ? 'ctx_' + chatId : null;
const ctx = ctxKey ? (staticData[ctxKey] || {}) : {};

// Si no tenemos fecha en el input, leerla de staticData
if (!fecha && ctx.fecha) fecha = ctx.fecha;
if (!rango && ctx.rango) rango = ctx.rango;

// Si nos llegó slot_numero, resolverlo a slot real desde los slots guardados
if (slotNumero && !slot) {
  const slotsGuardados = ctx.slots || [];
  const idx = slotNumero - 1;
  if (idx >= 0 && idx < slotsGuardados.length) {
    slot = slotsGuardados[idx].hora_inicio;
  }
}

// Defensa: parsear callbacks de slot (formato HH:MM:f:YYYY-MM-DD)
if (textRaw.startsWith('cmd:crear:slot:')) {
  const parsed = textRaw.substring('cmd:crear:slot:'.length);
  if (parsed !== 'none') {
    const fIdx = parsed.indexOf(':f:');
    if (fIdx >= 0) {
      slot = parsed.substring(0, fIdx);
      if (!fecha) fecha = parsed.substring(fIdx + 3);
    } else {
      slot = parsed;
    }
  }
}

// ======================================================================
// CÁLCULO DE FECHA
// ======================================================================

// Si hay rango y no hay fecha, calcular fecha exacta (en timezone Argentina)
if (!fecha && rango && rango !== 'exacto') {
  let daysToAdd = 0;
  if (rango === 'inmediato') daysToAdd = 1;
  else if (rango === '2semanas') daysToAdd = 14;
  else if (rango === '1mes') daysToAdd = 28;
  if (daysToAdd > 0) {
    fecha = addDays(hoyArgentina(), daysToAdd);
  }
}

// Si hay fechaRaw (input DD/MM/AAAA), validar y convertir
if (!fecha && fechaRaw) {
  const match = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(fechaRaw);
  if (match) {
    const day = parseInt(match[1], 10);
    const month = parseInt(match[2], 10) - 1;
    const year = parseInt(match[3], 10);
    const parsed = new Date(year, month, day);
    if (parsed.getDate() === day && parsed.getMonth() === month && parsed.getFullYear() === year) {
      const todayStr = hoyArgentina();
      const maxStr = addDays(todayStr, 90);  // ~3 meses
      const iso = String(year) + '-' + String(month + 1).padStart(2, '0') + '-' + String(day).padStart(2, '0');
      if (iso < todayStr) {
        accion = 'fecha_invalida';
        mensajeError = 'La fecha está en el pasado.';
      } else if (iso > maxStr) {
        accion = 'fecha_invalida';
        mensajeError = 'Solo podés reservar hasta 3 meses adelante.';
      } else {
        fecha = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
      }
    } else {
      accion = 'fecha_invalida';
      mensajeError = 'La fecha no es válida (día o mes incorrecto).';
    }
  } else {
    accion = 'fecha_invalida';
    mensajeError = 'Formato incorrecto. Usá DD/MM/AAAA (ej: 15/07/2026).';
  }
}

// ======================================================================
// GUARDAR EN STATIC DATA
// ======================================================================
if (ctxKey && fecha) {
  staticData[ctxKey] = {
    fecha: fecha,
    rango: rango,
    slots: ctx.slots || []
  };
}

// ======================================================================
// DECIDIR ACCIÓN FINAL
// ======================================================================
if (!accion) {
  if (rango === 'exacto' && !fecha) {
    accion = 'pedir_fecha';
  } else if (fecha && slot) {
    accion = 'crear_turno';
  } else if (fecha) {
    accion = 'pedir_slot';
  } else {
    accion = 'pedir_rango';
  }
}

return [{
  json: {
    chat_id: chatId,
    comando: comando,
    accion: accion,
    fecha: fecha,
    slot: slot,
    rango: rango,
    fecha_inicio: fecha || '',
    mensaje_error: mensajeError
  }
}];

// ======================================================================
// HELPERS
// ======================================================================
function addDays(yyyy_mm_dd, n) {
  const [y, m, d] = yyyy_mm_dd.split('-').map(Number);
  const date = new Date(Date.UTC(y, m - 1, d));
  date.setUTCDate(date.getUTCDate() + n);
  const yy = date.getUTCFullYear();
  const mm = String(date.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(date.getUTCDate()).padStart(2, '0');
  return `${yy}-${mm}-${dd}`;
}

// ======================================================================
// LEER SLOTS DEL HTTP RESPONSE
// ======================================================================
const items = $input.all();
let slots = [];

if (items.length > 0) {
  if (Array.isArray(items[0].json)) {
    slots = items[0].json;
  } else {
    slots = items.map(item => item.json);
  }
}
slots = slots.filter(function (s) { return s && s.disponible !== false; });

// chatId y fecha los leemos del Code - Decidir Paso (sobrevive al loop)
let chatId = '';
let fecha = '';
let fechaInicio = '';
try {
  const codeData = $('Code - Decidir Paso').first().json;
  if (codeData) {
    chatId = codeData.chat_id || '';
    fecha = codeData.fecha || '';
    fechaInicio = codeData.fecha_inicio || fecha;
  }
} catch (e) {
  // fallback silencioso
}

// ======================================================================
// STATIC DATA
// ======================================================================
const staticData = $getWorkflowStaticData('global');
const contadorKey = 'contador_' + chatId;
const ctxKey = chatId ? 'ctx_' + chatId : null;
let contador = staticData[contadorKey] || 0;

if (slots.length > 0) {
  // Guardar slots en staticData para resolver slot_numero después
  if (ctxKey) {
    const existing = staticData[ctxKey] || {};
    existing.slots = slots;
    staticData[ctxKey] = existing;
  }
  delete staticData[contadorKey];
  return [{
    json: {
      chat_id: chatId,
      fecha: fecha,
      fecha_inicio: fechaInicio,
      slots: slots,
      decision: 'found'
    }
  }];
}

// No hay slots. ¿Ya intentamos los 7 días?
const MAX_DIAS = 7;
if (contador >= MAX_DIAS - 1 || !fecha) {
  delete staticData[contadorKey];
  return [{
    json: {
      chat_id: chatId,
      fecha: fecha,
      fecha_inicio: fechaInicio,
      slots: [],
      decision: 'exhausted'
    }
  }];
}

// Retry: +1 día (usando helper, sin problemas de timezone)
staticData[contadorKey] = contador + 1;
const nextFecha = addDays(fecha, 1);
return [{
  json: {
    chat_id: chatId,
    fecha: nextFecha,
    fecha_inicio: fechaInicio,
    slots: [],
    decision: 'retry'
  }
}];

const input = ($input.all()[0] && $input.all()[0].json) || {};
const chatId = input.chat_id;
const fecha = input.fecha || '';
let slots = input.slots || [];
if (!Array.isArray(slots)) slots = [];
const disponibles = slots.filter(function (s) { return s.disponible !== false; });

// Un boton por slot (una fila cada uno). La FECHA viaja en el callback_data
// para que la seleccion sea STATELESS: no depende de $getWorkflowStaticData.
// Formato: cmd:crear:slot:HH:MM:f:YYYY-MM-DD  (<64 bytes, limite de Telegram)
const inlineKeyboard = disponibles.map(function (s) {
  return [{
    text: s.hora_inicio + (s.hora_fin ? ' - ' + s.hora_fin : ''),
    callback_data: 'cmd:crear:slot:' + s.hora_inicio + ':f:' + fecha
  }];
});

const texto = '\uD83D\uDD50 Horarios disponibles para el ' + fecha + ':\n\nElegi un horario \uD83D\uDC47';

// tg_body = payload listo para POST /sendMessage (lo envia el nodo HTTP siguiente)
return [{
  json: {
    chat_id: chatId,
    fecha: fecha,
    slots: disponibles,
    cantidad: disponibles.length,
    tg_body: {
      chat_id: chatId,
      text: texto,
      reply_markup: { inline_keyboard: inlineKeyboard }
    }
  }
}];

// Leer chat_id del Code - Decidir Paso (sobrevive al flow)
let chatId = '';
try {
  const codeData = $('Code - Decidir Paso').first().json;
  if (codeData) {
    chatId = codeData.chat_id || '';
  }
} catch (e) {
  // fallback silencioso
}

const input = ($input.all()[0] && $input.all()[0].json) || {};
const fecha = input.fecha;
const slot = input.hora_inicio || input.slot;
const turnoId = input.id;
const errorStatus = input.statusCode && input.statusCode >= 400;
const errorDetail = input.detail || (errorStatus ? 'Error HTTP ' + input.statusCode : null);

return [{
  json: {
    chat_id: chatId,
    fecha: fecha,
    slot: slot,
    turno_id: turnoId,
    exito: !!turnoId && !errorStatus,
    error: errorDetail
  }
}];
